import{_ as n,o as a,c as t,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"92. Demand Escalation Policy","description":"","frontmatter":{"title":"92. Demand Escalation Policy","eba":"Nurses and Midwives 2024-2028","topics":["consultation","union-matters","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/92-demand-escalation-policy.md","filePath":"ebas/nurses-midwives/classification-staffing/92-demand-escalation-policy.md"}'),s={name:"ebas/nurses-midwives/classification-staffing/92-demand-escalation-policy.md"};function o(r,e,p,l,c,d){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="_92-demand-escalation-policy" tabindex="-1">92. Demand Escalation Policy <a class="header-anchor" href="#_92-demand-escalation-policy" aria-label="Permalink to &quot;92. Demand Escalation Policy&quot;">​</a></h1><p><strong>92.1</strong> Each Employer will maintain and apply a demand escalation policy in accordance with this clause.</p><p><strong>92.2</strong> Demand escalation policies will be developed and revised in consultation with Employees and the Union.</p><p><strong>92.3</strong> Employers and the Union understand the potential impact unplanned increases in demand have on both patient and Employee safety. The purpose of this clause is to promote:</p><p><strong>(a)</strong> safe patient care;</p><p><strong>(b)</strong> staff safety; and</p><p><strong>(c)</strong> a risk management framework in managing an increase in demand.</p><p><strong>92.4</strong> Principles of policy</p><p><strong>(a)</strong> Health Services will experience unplanned increases in demand.</p><p><strong>(b)</strong> The appropriate planning and recording of escalation plans will assist in responding to such demand and in the process promote the health and safety of staff and patients.</p><p><strong>(c)</strong> Collaborative risk assessments should inform the development of such plans.</p><p><strong>(d)</strong> Employees need to have access to escalation plans and the process for implementing the escalation plan so there is minimum delay in the Health Service responding to increases in demand.</p><p><strong>(e)</strong> The operation of the escalation plan will be dependent on collaboration between Health Service nursing and midwifery senior managers and Ward/Unit Management on a shift by shift basis, taking into account matters including occupancy and patient acuity.</p><p><strong>92.5</strong> Each Employer will have policies, developed in consultation with Employees and the Union, which set out the precise process to be followed to ensure patient and staff safety when:</p><p><strong>(a)</strong> service demand is approaching capacity; and</p><p><strong>(b)</strong> there is an identified risk to patient or Employee safety (examples of patient cohorts which potentially carry additional risks are bariatric patients, cognitive impairment patients and aggressive patients).</p><p><strong>92.6</strong> The policy will have considered relevant risk assessments, in particular where circumstances require nursing/midwifery care to be provided in an alternative environment, and relevant legislation, regulations or guidelines.</p><p><strong>92.7</strong> The policy will encapsulate the principles set out in clause 92.4 above and contain specific information which sets out the following:</p><p><strong>(a)</strong> the trigger point(s) for the activation of the policy, noting that these trigger points should act as an early warning system;</p><p><strong>(b)</strong> the accountabilities of those Employees involved in the decision making process;</p><p><strong>(c)</strong> the process to be followed for those responsible for implementing the process, including the means to access additional, immediate and appropriate resources including appropriately qualified nursing staff;</p><p><strong>(d)</strong> the identification of any alternative environment whereby nursing/midwifery care may be provided;</p><p><strong>(e)</strong> the process for orientating staff to the alternative area and the requirement to perform a risk assessment in circumstances where one has not been completed; and</p><p><strong>(f)</strong> the de-escalation process.</p><p>Plain language terms: surge plan, escalation, high demand.</p>',25)])])}const h=n(s,[["render",o]]);export{m as __pageData,h as default};
